import networkx as nx

def is_snark(graph):
    if not nx.is_regular(graph, 3):
        return False  # Not cubic
    if not nx.is_3_edge_connected(graph):
        return False  # Not cyclically 4-edge-connected
    if nx.edge_chromatic_number(graph) != 4:
        return False  # Edge chromatic number is not 4
    if nx.girth(graph) < 5:
        return False  # Girth less than 5
    return True

# Example usage:
G = nx.petersen_graph()
print(is_snark(G))  # Output: True
